function shouldGeneratePlan(messages) {
  if (messages.length < 2) return false;
  const lastAssistant = [...messages].reverse().find(m => m.role === 'assistant');
  if (!lastAssistant) return false;
  const text = lastAssistant.content.toLowerCase();
  return text.includes('tamamdır, plan') ||
         text.includes('planını hazırlıyorum') ||
         text.includes('preparing your plan') ||
         text.includes('let me put') ||
         text.includes('drafting your plan');
}

// Detect cities mentioned anywhere in the conversation
function detectMentionedCities(messages) {
  const allText = messages.map(m => m.content).join(' ').toLowerCase();
  const found = new Set();

  for (const slug of Object.keys(CITY_NAMES)) {
    const display = CITY_NAMES[slug].toLowerCase();
    const ascii = slug.replace(/-/g, ' ');
    // Check several name variants
    if (allText.includes(slug) || allText.includes(display) || allText.includes(ascii)) {
      found.add(slug);
    }
  }

  // Aliases
  const aliases = {
    "kapadokya": "cappadocia",
    "istanbul": "istanbul",
    "izmir": "izmir",
    "antalya": "antalya",
    "fethiye": "mugla",
    "bodrum": "mugla",
    "marmaris": "mugla",
    "ölüdeniz": "mugla",
    "oludeniz": "mugla",
    "pamukkale": "denizli",
    "ephesus": "izmir",
    "efes": "izmir",
    "alacati": "izmir",
    "alaçatı": "izmir",
    "ayvalik": "balikesir",
    "ayvalık": "balikesir",
    "uzungöl": "trabzon",
    "uzungol": "trabzon",
    "ayder": "rize",
    "göbekli": "sanliurfa",
    "gobekli": "sanliurfa"
  };
  for (const [alias, slug] of Object.entries(aliases)) {
    if (allText.includes(alias)) found.add(slug);
  }

  return [...found];
}

// Detect interests mentioned in conversation
function detectInterests(messages) {
  const allText = messages.map(m => m.content).join(' ').toLowerCase();
  const interests = new Set();

  const interestKeywords = {
    "history":      ["tarih", "history", "antik", "ancient", "müze", "museum", "kale", "castle"],
    "food":         ["yemek", "food", "cuisine", "gastronomy", "restaurant", "kebap", "kebab"],
    "nature":       ["doğa", "doga", "nature", "yürüyüş", "hiking", "yayla", "highland", "milli park"],
    "beach":        ["sahil", "beach", "plaj", "deniz", "sea", "coast", "adası", "island"],
    "photography":  ["fotoğraf", "fotograf", "photo", "photography", "cinematic"],
    "adventure":    ["macera", "adventure", "rafting", "trek", "kayak", "ski"],
    "culture":      ["kültür", "kultur", "culture", "art", "sanat", "müzik"],
    "architecture": ["mimari", "architecture", "cami", "mosque", "saray", "palace"],
    "romantic":     ["romantik", "romantic", "balayı", "honeymoon", "couple", "çift"],
    "spiritual":    ["sufi", "mevlana", "rumi", "spiritual", "manastır", "monastery"],
    "ski":          ["kayak", "ski", "snow", "kar"],
    "summer":       ["yaz", "summer", "tatil", "july", "august", "temmuz", "ağustos"]
  };

  for (const [interest, keywords] of Object.entries(interestKeywords)) {
    if (keywords.some(kw => allText.includes(kw))) {
      interests.add(interest);
    }
  }

  return [...interests];
}

// RAG: Select 3-7 cities relevant to user's preferences
function selectRelevantCities(messages) {
  // 1. Use explicitly mentioned cities first (always include)
  const mentioned = detectMentionedCities(messages);

  // 2. Detect interests
  const interests = detectInterests(messages);

  // 3. Score remaining cities by interest match
  const scores = {};
  for (const [slug, profile] of Object.entries(CITY_PROFILES)) {
    if (mentioned.includes(slug)) continue; // already included
    const matchCount = profile.filter(t => interests.includes(t)).length;
    scores[slug] = matchCount;
  }

  // 4. Pick top 3-5 additional cities (in addition to mentioned ones)
  const sorted = Object.entries(scores)
    .filter(([_, s]) => s > 0)
    .sort(([, a], [, b]) => b - a)
    .map(([slug]) => slug);

  const additionalCount = Math.max(0, Math.min(5, 7 - mentioned.length));
  const additional = sorted.slice(0, additionalCount);

  let result = [...mentioned, ...additional];

  // 5. If still empty (no mentions, no interests detected), default to flagship cities
  if (result.length === 0) {
    result = ["istanbul", "cappadocia", "antalya", "mugla", "izmir"];
  }

  return result;
}

function buildRagContext(citySlugs) {
  const blocks = [];
  blocks.push("# AVAILABLE CITY CONTEXTS\n\nThe following are the verified city descriptions from showmeturkiye.com. Use ONLY information from these blocks. Do not invent details about any city.\n");

  for (const slug of citySlugs) {
    if (CITY_CONTEXTS[slug]) {
      blocks.push(`---\n\n${CITY_CONTEXTS[slug]}`);
    }
  }

  return blocks.join("\n\n");
}

// ════════════════════════════════════════════════════
// MAIN HANDLER
// ════════════════════════════════════════════════════

const HAIKU = "claude-haiku-4-5-20251001";
const SONNET = "claude-sonnet-4-5";

export default {
  async fetch(request, env) {
    const origin = request.headers.get("Origin") || "";
    const headers = corsHeaders(origin);

    if (request.method === "OPTIONS") {
      return new Response(null, { headers });
    }

    if (request.method !== "POST") {
      return new Response("Method not allowed", { status: 405, headers });
    }

    const ip = request.headers.get("CF-Connecting-IP") || "unknown";
    if (!checkRateLimit(ip)) {
      return new Response(
        JSON.stringify({ error: "Çok hızlı gidiyorsun, biraz nefes al." }),
        { status: 429, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }

    let body;
    try {
      body = await request.json();
    } catch (e) {
      return new Response(
        JSON.stringify({ error: "Invalid request" }),
        { status: 400, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }

    const { messages, stream } = body;
    if (!Array.isArray(messages) || messages.length === 0) {
      return new Response(
        JSON.stringify({ error: "messages array required" }),
        { status: 400, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }

    if (messages.length > 40) {
      return new Response(
        JSON.stringify({ error: "Sohbet çok uzadı, sıfırlayıp baştan başla." }),
        { status: 400, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }

    for (const m of messages) {
      if (!m.role || !m.content || typeof m.content !== "string") {
        return new Response(
          JSON.stringify({ error: "Invalid message format" }),
          { status: 400, headers: { ...headers, "Content-Type": "application/json" } }
        );
      }
      if (m.content.length > 4000) {
        return new Response(
          JSON.stringify({ error: "Message too long" }),
          { status: 400, headers: { ...headers, "Content-Type": "application/json" } }
        );
      }
      if (m.role === "ai") m.role = "assistant";
    }

    if (!env.ANTHROPIC_API_KEY) {
      return new Response(
        JSON.stringify({ error: "Server misconfigured" }),
        { status: 500, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }

    const useStreaming = stream === true;
    const trimmedMessages = trimHistory(messages);

    // ═══════════════════════════════════════════════
    // ROUTING — Layer 1 (dialog) or Layer 2 (plan)?
    // ═══════════════════════════════════════════════

    const generatePlan = shouldGeneratePlan(trimmedMessages);

    let systemBlocks;
    let model;
    let max_tokens;

    if (generatePlan) {
      // ═══ LAYER 2: PLAN ═══
      // Use Sonnet (better structure), inject RAG city contexts
      const cities = selectRelevantCities(trimmedMessages);
      const ragContext = buildRagContext(cities);

      console.log(`[PLAN] Selected cities: ${cities.join(', ')}`);

      systemBlocks = [
        {
          type: "text",
          text: PLAN_PROMPT
        },
        {
          type: "text",
          text: ragContext,
          cache_control: { type: "ephemeral" }
        }
      ];
      model = SONNET;
      max_tokens = 4000;
    } else {
      // ═══ LAYER 1: DIALOG ═══
      // Use Haiku (cheap, fast), no city contexts needed
      systemBlocks = [
        {
          type: "text",
          text: DIALOG_PROMPT,
          cache_control: { type: "ephemeral" }
        }
      ];
      model = HAIKU;
      max_tokens = 600;
    }

    try {
      const apiResponse = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": env.ANTHROPIC_API_KEY,
          "anthropic-version": "2023-06-01"
        },
        body: JSON.stringify({
          model: model,
          max_tokens: max_tokens,
          system: systemBlocks,
          messages: trimmedMessages,
          stream: useStreaming
        })
      });

      if (!apiResponse.ok) {
        const errorText = await apiResponse.text();
        console.error("Anthropic API error:", apiResponse.status, errorText);
        return new Response(
          JSON.stringify({ error: "AI hizmeti şu an cevap vermiyor, biraz sonra tekrar dene." }),
          { status: 502, headers: { ...headers, "Content-Type": "application/json" } }
        );
      }

      if (useStreaming) {
        return new Response(apiResponse.body, {
          headers: {
            ...headers,
            "Content-Type": "text/event-stream",
            "Cache-Control": "no-cache",
            "Connection": "keep-alive"
          }
        });
      }

      const data = await apiResponse.json();
      const reply = data.content?.[0]?.text || "Cevap üretilemedi, tekrar dene.";

      if (data.usage) {
        console.log(`[${model}] layer=${generatePlan ? 'PLAN' : 'DIALOG'} cache_creation=${data.usage.cache_creation_input_tokens || 0} cache_read=${data.usage.cache_read_input_tokens || 0} input=${data.usage.input_tokens || 0} output=${data.usage.output_tokens || 0}`);
      }

      return new Response(
        JSON.stringify({ reply }),
        { headers: { ...headers, "Content-Type": "application/json" } }
      );

    } catch (error) {
      console.error("Worker error:", error);
      return new Response(
        JSON.stringify({ error: "Bir şeyler ters gitti, tekrar dene." }),
        { status: 500, headers: { ...headers, "Content-Type": "application/json" } }
      );
    }
  }
};
